// Reescribe el index.ts de lib/api-zod tras correr orval para garantizar
// que reexporta limpiamente los schemas generados.
import { writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const target = join(__dirname, "..", "..", "api-zod", "src", "index.ts");

const content = [
  "// AUTO-GENERATED by lib/api-spec/scripts/patch-api-zod.mjs — do not edit by hand.",
  "// Re-exports the Zod schemas produced by Orval. Run `pnpm codegen` to refresh.",
  'export * from "./generated/api.js";',
  "",
].join("\n");

writeFileSync(target, content, "utf8");
console.log(`[patch-api-zod] wrote ${target}`);
